#include <stdio.h>
#include <stdlib.h>

// Function to print array elements
void printArray(int *arr, int size) {
 printf("Array elements: ");
 for (int i = 0; i < size; i++) {
 printf("%d ", arr[i]);
 }
 printf("\n");
}

int main() {
 int initialSize = 5;
 int newSize = 10;
 int *ptr = NULL;

 // ========== MALLOC EXAMPLE ==========
 // Allocate memory for 5 integers using malloc
 // malloc returns uninitialized memory (garbage values)
 printf("=== Using malloc() ===\n");
 ptr = (int*)malloc(initialSize * sizeof(int));

 // Always check if allocation succeeded
 if (ptr == NULL) {
 printf("Error: Memory allocation failed!\n");
 return 1;
 }

 // Initialize the allocated memory
 printf("After malloc, before initialization:\n");
 printf(" Values (uninitialized): ");
 for (int i = 0; i < initialSize; i++) {
 printf("%d ", ptr[i]); // May show garbage values
 }
 printf("\n");

 // Initialize with values
 for (int i = 0; i < initialSize; i++) {
 ptr[i] = (i + 1) * 10;
 }
 printArray(ptr, initialSize);

 // ========== REALLOC EXAMPLE ==========
 // Resize the allocated memory block to hold 10 integers
 printf("\n=== Using realloc() ===\n");
 int *tempPtr = (int*)realloc(ptr, newSize * sizeof(int));

 if (tempPtr == NULL) {
 printf("Error: Reallocation failed!\n");
 free(ptr); // Free original memory before exiting
 return 1;
 }

 ptr = tempPtr; // Update pointer to new memory location

 // Initialize new elements (old values are preserved)
 for (int i = initialSize; i < newSize; i++) {
 ptr[i] = (i + 1) * 10;
 }

 printf("After realloc to %d elements:\n", newSize);
 printArray(ptr, newSize);

 // ========== CALLOC EXAMPLE ==========
 // Allocate and zero-initialize memory for array
 printf("\n=== Using calloc() ===\n");
 int *arr = (int*)calloc(5, sizeof(int));

 if (arr == NULL) {
 printf("Error: Memory allocation failed!\n");
 free(ptr);
 return 1;
 }

 // calloc initializes all bytes to zero
 printf("After calloc (zero-initialized):\n");
 printArray(arr, 5); // All values will be 0

 // ========== FREE EXAMPLE ==========
 // Deallocate all dynamically allocated memory
 printf("\n=== Using free() ===\n");
 free(ptr);
 ptr = NULL; // Good practice: prevent dangling pointer

 free(arr);
 arr = NULL; // Set to NULL after freeing

 printf("Memory freed successfully!\n");
 printf("ptr is now: %s\n", ptr == NULL ? "NULL" : "not NULL");
 printf("arr is now: %s\n", arr == NULL ? "NULL" : "not NULL");

 return 0;
}

#include <stdio.h>
#include <stdlib.h>

// Define the node structure for a linked list
struct Node {
 int data;
 struct Node* next;
};

// Function to create a new node using malloc
struct Node* createNode(int value) {
 // Allocate memory for a new node
 struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));

 // Check if allocation succeeded
 if (newNode == NULL) {
 printf("Error: Could not allocate memory for new node\n");
 return NULL;
 }

 // Initialize node data
 newNode->data = value;
 newNode->next = NULL;

 return newNode;
}

// Function to insert a node at the beginning
struct Node* insertAtBeginning(struct Node* head, int value) {
 struct Node* newNode = createNode(value);
 if (newNode == NULL) {
 return head;
 }

 // Point new node to current head
 newNode->next = head;

 return newNode; // New node becomes the new head
}

// Function to insert at the end of the list
struct Node* insertAtEnd(struct Node* head, int value) {
 struct Node* newNode = createNode(value);
 if (newNode == NULL) {
 return head;
 }

 // If list is empty, new node becomes head
 if (head == NULL) {
 return newNode;
 }

 // Traverse to the last node
 struct Node* current = head;
 while (current->next != NULL) {
 current = current->next;
 }

 // Link the last node to new node
 current->next = newNode;

 return head;
}

// Function to delete a node with given value
struct Node* deleteNode(struct Node* head, int value) {
 if (head == NULL) {
 return NULL;
 }

 // If head node contains the value
 if (head->data == value) {
 struct Node* temp = head;
 head = head->next;
 free(temp); // Free the memory of deleted node
 return head;
 }

 // Search for the node to delete
 struct Node* current = head;
 while (current->next != NULL && current->next->data != value) {
 current = current->next;
 }

 // If node found, delete it
 if (current->next != NULL) {
 struct Node* temp = current->next;
 current->next = temp->next;
 free(temp); // Free the memory
 }

 return head;
}

// Function to free entire linked list (prevent memory leaks)
void freeList(struct Node* head) {
 struct Node* current = head;

 while (current != NULL) {
 struct Node* nextNode = current->next;
 free(current); // Free each node
 current = nextNode;
 }

 printf("Entire linked list freed - no memory leak!\n");
}

// Function to display the linked list
void displayList(struct Node* head) {
 if (head == NULL) {
 printf("List is empty\n");
 return;
 }

 printf("Linked List: ");
 struct Node* current = head;
 while (current != NULL) {
 printf("%d -> ", current->data);
 current = current->next;
 }
 printf("NULL\n");
}

// Main function demonstrating dynamic memory in linked lists
int main() {
 struct Node* head = NULL;

 printf("=== Dynamic Memory in Linked Lists ===\n\n");

 // Insert elements at the beginning
 printf("Inserting 30, 20, 10 at beginning:\n");
 head = insertAtBeginning(head, 10);
 head = insertAtBeginning(head, 20);
 head = insertAtBeginning(head, 30);
 displayList(head);

 // Insert elements at the end
 printf("\nInserting 40, 50 at end:\n");
 head = insertAtEnd(head, 40);
 head = insertAtEnd(head, 50);
 displayList(head);

 // Delete a node
 printf("\nDeleting node with value 20:\n");
 head = deleteNode(head, 20);
 displayList(head);

 // Free the entire list to prevent memory leak
 printf("\nFreeing the list:\n");
 freeList(head);
 head = NULL; // Avoid dangling pointer

 return 0;
}
